display.text:
package com.khoablabla.pvpbot.traits;

import net.citizensnpcs.api.npc.NPC;
import net.citizensnpcs.api.trait.Trait;

import org.bukkit.Bukkit;
import org.bukkit.entity.Player;
import org.bukkit.plugin.java.JavaPlugin;

import com.khoablabla.pvpbot.PvPBot;

public class PvPBotTrait extends Trait {

    private int tickCounter = 0;

    public PvPBotTrait() {
        super("pvpbot");
    }

    @Override
    public void onAttach() {
        if (npc.getEntity() instanceof Player) {
            JavaPlugin plugin = JavaPlugin.getPlugin(PvPBot.class);
            plugin.getLogger().info("PvPBotTrait attached to NPC " + npc.getName() + " (ID: " + npc.getId() + ")");
        } else if (npc.getEntity() != null) {
            JavaPlugin plugin = JavaPlugin.getPlugin(PvPBot.class);
            plugin.getLogger().warning("PvPBotTrait attached to NPC " + npc.getName()
                    + " (ID: " + npc.getId() + ") but its entity is not a Player вҖ” PvP functionality may be limited.");
        }
    }

    @Override
    public void onSpawn() {
        if (npc.getEntity() instanceof Player player) {
            npc.setProtected(false);
            npc.data().set(NPC.Metadata.DAMAGE_BY_PLAYER, true);

            JavaPlugin plugin = JavaPlugin.getPlugin(PvPBot.class);
            plugin.getLogger().info("PvPBot NPC '" + npc.getName() + "' (ID: " + npc.getId()
                    + ") has spawned in world: " + player.getWorld().getName());
        }
    }

    @Override
    public void onDespawn() {
        JavaPlugin plugin = JavaPlugin.getPlugin(PvPBot.class);
        plugin.getLogger().info("PvPBot NPC (ID: " + npc.getId() + ") has despawned from world.");
    }

    @Override
    public void run() {
        tickCounter++;
        if (tickCounter % 100 != 0) return;

        if (npc.getEntity() instanceof Player player) {
            double health = player.getHealth();
            Bukkit.getLogger().info("[PvPBot] " + npc.getName() + " (ID: " + npc.getId()
                    + ") is alive with HP: " + health);
        }
    }
}

input.content:
plugins {
    id 'java'
    id 'application'
}

group = 'com.pvpbot'
version = '1.0.0'

java {
    sourceCompatibility = JavaVersion.VERSION_25
    targetCompatibility = JavaVersion.VERSION_25
}

repositories {
    mavenCentral()
    maven { url 'https://repo.papermc.io/repository/maven-public/' }
    maven { url 'https://ci.citizensnpcs.co/job/Citizens2/artifact/' }
    maven { url 'https://repo.dmulloy2.net/nexus/content/repositories/public/' }
}

dependencies {
    compileOnly 'io.papermc.paper:paper-api:1.21.11-R0.1-SNAPSHOT'
    compileOnly 'net.citizensnpcs:citizens-api:2.0.37-SNAPSHOT'
    compileOnly 'com.comphenix.protocol:ProtocolLib:5.3.0'
    testImplementation 'org.junit.jupiter:junit-jupiter:5.10.2'
}

tasks.withType(JavaCompile) {
    options.encoding = 'UTF-8'
    options.compilerArgs << '-Xlint:unchecked' << '-Xlint:deprecation'
}

test {
    useJUnitPlatform()
}

jar {
    manifest {
        attributes(
            'Main-Class': 'com.khoablabla.pvpbot.PvPBot',
            'Plugin-Name': 'PvPBot',
            'Plugin-Version': version,
            'Plugin-Main': 'com.khoablabla.pvpbot.PvPBot',
            'Plugin-API-Version': '1.21',
            'Plugin-Depend': 'Citizens',
            'Plugin-SoftDepend': 'ProtocolLib'
        )
    }
    from {
        configurations.compileOnly.collect { it.isDirectory() ? it : zipTree(it) }
    }
}

