package com.khoablabla.pvpbot.combat;

import net.citizensnpcs.api.npc.NPC;

import org.bukkit.Material;
import org.bukkit.entity.LivingEntity;
import org.bukkit.entity.Player;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.PlayerInventory;

public class ShieldBreaker {

    public void checkAndSwap(NPC npc, LivingEntity target) {
        if (!npc.isSpawned() || !(npc.getEntity() instanceof Player botPlayer)) return;

        PlayerInventory inv = botPlayer.getInventory();
        ItemStack mainHand = inv.getItemInMainHand();

        boolean isBlocking = false;
        if (target instanceof Player targetPlayer) {
            // Check if player is blocking with shield
            if (targetPlayer.isBlocking()) {
                isBlocking = true;
            } else {
                ItemStack offHand = targetPlayer.getInventory().getItemInOffHand();
                if (offHand != null && offHand.getType().name().contains("SHIELD")) {
                    isBlocking = true;
                }
            }
        }

        if (isBlocking && !isAxe(mainHand)) {
            // Target is blocking, swap to axe
            for (ItemStack item : inv.getContents()) {
                if (item != null && isAxe(item)) {
                    inv.setItemInMainHand(item);
                    return;
                }
            }
        } else if (!isBlocking && isAxe(mainHand)) {
            // Target not blocking, swap back to sword
            for (ItemStack item : inv.getContents()) {
                if (item != null && isSword(item)) {
                    inv.setItemInMainHand(item);
                    return;
                }
            }
        }
    }

    private boolean isAxe(ItemStack item) {
        Material type = item.getType();
        return type == Material.WOODEN_AXE || type == Material.STONE_AXE
                || type == Material.IRON_AXE || type == Material.GOLDEN_AXE
                || type == Material.DIAMOND_AXE || type == Material.NETHERITE_AXE;
    }

    private boolean isSword(ItemStack item) {
        Material type = item.getType();
        return type == Material.WOODEN_SWORD || type == Material.STONE_SWORD
                || type == Material.IRON_SWORD || type == Material.GOLDEN_SWORD
                || type == Material.DIAMOND_SWORD || type == Material.NETHERITE_SWORD;
    }
}

