        if (getServer().getPluginManager().isPluginEnabled("ProtocolLib")) {
            getLogger().info("ProtocolLib detected вҖ” advanced packet features available.");
        } else {
            getLogger().info("ProtocolLib not detected вҖ” packet features will be unavailable.");
        }
