        }

        if (args.length == 0) {
            sender.sendMessage("Usage: /pvpbot spawn [name|number] [name2...] | /pvpbot remove [name] | /pvpbot removeall | /pvpbot tp <name>");
            return true;
        }

        return switch (args[0].toLowerCase()) {
            case "spawn" -> handleSpawn(sender, args);
            case "remove" -> handleRemove(sender, args);
            case "removeall" -> handleRemoveAll(sender);
            case "tp" -> handleTeleport(sender, args);
            default -> {
                sender.sendMessage("Unknown subcommand. Usage: /pvpbot spawn [name|number] [name2...] | /pvpbot remove [name] | /pvpbot removeall | /pvpbot tp <name>");
                yield true;
            }
        };
    }

    private boolean handleSpawn(CommandSender sender, String[] args) {
        if (!(sender instanceof Player player)) {
            sender.sendMessage("Only players can spawn bots.");
            return true;
