            }
            player.sendMessage("Spawned PvPBot '" + name + "'");
            return true;
        }

        if (args.length == 2) {
            try {
                int count = Integer.parseInt(args[1]);
                count = Math.max(1, Math.min(50, count));
                int spawned = 0;
                for (int i = 0; i < count; i++) {
                    String name = generateUniqueRealisticName();
                    if (spawnSingleBot(player, name)) {
                        spawned++;
                        Bukkit.getServer().broadcastMessage("В§e" + name + " joined the game");
                    }
                }
                player.sendMessage("Spawned " + spawned + " random PvPBot(s).");
                return true;
            } catch (NumberFormatException e) {
                String name = args[1];
                if (name.contains("<") || name.contains(">")) {
                    player.sendMessage("В§c[PvPBot] Invalid name '" + name + "' вҖ” name must not contain brackets.");
                    return true;
                }
                if (isNameTaken(name)) {
                    player.sendMessage("В§c[PvPBot] A bot with the name '" + name + "' already exists!");
                    return true;
                }
                if (spawnSingleBot(player, name)) {
                    Bukkit.getServer().broadcastMessage("В§e" + name + " joined the game");
                }
                player.sendMessage("Spawned PvPBot '" + name + "'");
                return true;
            }
        }

        int spawned = 0;
        for (int i = 1; i < args.length; i++) {
            String name = args[i];
            if (name.contains("<") || name.contains(">")) {
                player.sendMessage("В§c[PvPBot] Skipping '" + name + "' вҖ” name must not contain brackets.");
                continue;
            }
            if (isNameTaken(name)) {
                player.sendMessage("В§c[PvPBot] Skipping '" + name + "' вҖ” a bot with that name already exists.");
                continue;
            }
            if (spawnSingleBot(player, name)) {
