        }
        return true;
    }

    private boolean isNameTaken(String name) {
        for (NPC npc : CitizensAPI.getNPCRegistry()) {
            if (npc.hasTrait(PvPBotTrait.class) && npc.getName().equalsIgnoreCase(name)) {
                return true;
            }
        }
        return false;
    }

    private String generateUniqueRealisticName() {
        String[] prefixes = {"Bread", "Beard", "Steve", "Alex", "Miner", "Slayer", "Gamer", "Hunter", "Pvp", "Pro", "Craft", "Knight"};
        String[] suffixes = {"1412", "99", "123", "77", "88", "_pvp", "_pro", "_gg", "456", "321"};

        String name;
        int attempts = 0;
        do {
            String prefix = prefixes[random.nextInt(prefixes.length)];
            String suffix = suffixes[random.nextInt(suffixes.length)];
            name = prefix + suffix;
            attempts++;
        } while (isNameTaken(name) && attempts < 100);

        return name;
    }

    private boolean handleRemove(CommandSender sender, String[] args) {
        if (args.length >= 2) {
            String name = args[1];
            NPC npc = findPvPBotByName(name);
            if (npc == null) {
                sender.sendMessage("В§c[PvPBot] No PvPBot named '" + name + "' found.");
                return true;
            }
            Bukkit.getServer().broadcastMessage("В§e" + npc.getName() + " left the game");
            npc.destroy();
            sender.sendMessage("Removed PvPBot '" + name + "'");
            return true;
        }

        if (!(sender instanceof Player player)) {
            sender.sendMessage("Only players can use this command.");
            return true;
        }

        Entity target = player.getTargetEntity(MAX_TARGET_DISTANCE);
        if (target == null || !CitizensAPI.getNPCRegistry().isNPC(target)) {
            sender.sendMessage("No PvPBot found in your line of sight.");
            return true;
        }

        NPC npc = CitizensAPI.getNPCRegistry().getNPC(target);
        if (!npc.hasTrait(PvPBotTrait.class)) {
            sender.sendMessage("That NPC is not a PvPBot.");
            return true;
        }

        Bukkit.getServer().broadcastMessage("В§e" + npc.getName() + " left the game");
        npc.destroy();
        sender.sendMessage("Removed PvPBot (ID: " + npc.getId() + ")");
        return true;
    }

    private boolean handleRemoveAll(CommandSender sender) {
        int removed = 0;
        for (NPC npc : CitizensAPI.getNPCRegistry()) {
            if (npc.hasTrait(PvPBotTrait.class)) {
                Bukkit.getServer().broadcastMessage("В§e" + npc.getName() + " left the game");
                npc.destroy();
                removed++;
            }
        }
        sender.sendMessage("Removed " + removed + " PvPBot(s).");
        return true;
    }

    private boolean handleTeleport(CommandSender sender, String[] args) {
        if (!(sender instanceof Player player)) {
            sender.sendMessage("Only players can use this command.");
            return true;
        }

        if (args.length < 2) {
            sender.sendMessage("Usage: /pvpbot tp <botName>");
            return true;
        }

        String name = args[1];
        NPC npc = findPvPBotByName(name);
        if (npc == null || !npc.isSpawned()) {
            sender.sendMessage("В§c[PvPBot] PvPBot named '" + name + "' is not active or spawned!");
            return true;
        }

        player.teleport(npc.getEntity().getLocation());
        sender.sendMessage("Teleported to PvPBot '" + name + "'");
        return true;
    }

    private NPC findPvPBotByName(String name) {
        for (NPC npc : CitizensAPI.getNPCRegistry()) {
            if (npc.hasTrait(PvPBotTrait.class) && npc.getName().equalsIgnoreCase(name)) {
                return npc;
            }
        }
        return null;
    }

    @Override
    public List<String> onTabComplete(CommandSender sender, Command command, String alias, String[] args) {
        if (args.length == 1) {
            String partial = args[0].toLowerCase();
            return List.of("spawn", "remove", "removeall", "tp").stream()
                    .filter(s -> s.startsWith(partial))
                    .toList();
        }

        if (args.length == 2) {
            String sub = args[0].toLowerCase();
            if (sub.equals("tp") || sub.equals("remove")) {
                String partial = args[1].toLowerCase();
                List<String> activeBotNames = new ArrayList<>();
                for (NPC npc : CitizensAPI.getNPCRegistry()) {
                    if (npc.hasTrait(PvPBotTrait.class) && npc.isSpawned()) {
